flowchart TD
    StartProcess["Start Card Check Request (T-UC-01)"] --> DecipherReq["Decipher & Log Request (T-REQ-015)"];
    DecipherReq --> ValidateSyntax["Validate Syntax & Assign TCNRefId"];
    ValidateSyntax --> BuildSubReq["Build Sub-Requests & Compute Search Keys (T-REQ-011)"];
    BuildSubReq --> ForEachMS{"For Each Member State ID?"};
    ForEachMS -- "Yes" --> EncryptSend["Encrypt & Send Sub-Request (T-REQ-003)"];
    EncryptSend --> WaitForReply["Wait For Reply (T-REQ-005)"];
    WaitForReply --> CollectReplies["Collect Replies"];
    CollectReplies --> ForEachMS;
    ForEachMS -- "No" --> AggregateRes["Aggregate All Responses"];
    AggregateRes --> FinalResponse["Send Final Response (T-REQ-003)"];
    FinalResponse --> EndProcess["End Process"];

flowchart TD
    A["Application Start"] --> B{"Initialize GUI Library?"}
    B -->|Yes| C["Call GUIXMain()"]
    C --> D["Initialize GTK Environment"]
    D --> E["Create Main Window"]
    E --> F{"Enter Message Loop (GUIWinMessageLoop())"}
    F --> G{"Event Received?"}
    G -->|Yes| H["Handle Event"]
    H --> F
    G -->|No| I{"Quit Message?"}
    I -->|No| F
    I -->|Yes| J["Cleanup Resources"]
    J --> K["Application End"]

